import org.owasp.encoder.Encode;

import java.io.IOException;
import java.io.PrintWriter;

public class XSSExample {
    public static void main(String[] args) throws IOException {
        // Simulating user input from a form or URL parameter
        String userInput = "<script>alert('XSS Attack!');</script>";

        // Properly encoding user input to prevent XSS
        String encodedUserInput = Encode.forHtml(userInput);

        // Constructing the output with encoded user input
        String output = "<p>Welcome, " + encodedUserInput + "</p>";

        // Writing the output to the response
        PrintWriter out = new PrintWriter(System.out);
        out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
